{
    bool      dccResult = false;
    float32_t fclk0     = (float32_t)xtalClk/1000000.0f;
    float32_t fclk1     = 10.0f;
    uint32_t  clkSource;
    //
    //  Read clock source, continue only for XTAL
    //
    clkSource = \
        (HWREG(DEVCFG_BASE + SYSCTL_O_CLKSRCCTL1) & SYSCTL_CLKSRCCTL1_OSCCLKSRCSEL_M) >> \
            SYSCTL_CLKSRCCTL1_OSCCLKSRCSEL_S;
    if(0x1U == clkSource)
    {
        //
        //  Verify parameters
        //
        ASSERT(0U != xtalClk);
        ASSERT(DCC_isBaseValid(dccBase));
        //
        // Enable peripheral clock to DCC
        //
        if(dccBase == DCC1_BASE)
        {
            SysCtl_enablePeripheral(SYSCTL_PERIPH_CLK_DCC1);
        }
        else if(dccBase == DCC2_BASE)
        {
            SysCtl_enablePeripheral(SYSCTL_PERIPH_CLK_DCC2);
        }
        else
        {
            SysCtl_enablePeripheral(SYSCTL_PERIPH_CLK_DCC3);
        }
        //
        //  10 cycles delay after enabling the peripheral
        //
        SysCtl_delay(4U);
        //
        //  DCC verfication
        //
        dccResult = DCC_verifyClockFrequency(
                                dccBase,
                                DCC_COUNT1SRC_INTOSC2,
                                fclk1,
                                DCC_COUNT0SRC_XTAL,
                                fclk0,
                                1.0f,
                                4.0f,
                                fclk0);
        //
        // Disable peripheral clock to DCC
        //
        if(dccBase == DCC1_BASE)
        {
            SysCtl_disablePeripheral(SYSCTL_PERIPH_CLK_DCC1);
        }
        else if(dccBase == DCC2_BASE)
        {
            SysCtl_disablePeripheral(SYSCTL_PERIPH_CLK_DCC2);
        }
        else
        {
            SysCtl_disablePeripheral(SYSCTL_PERIPH_CLK_DCC3);
        }
    }
    else
    {
        //
        //  Non XTAL clock sources
        //
        dccResult = true;
    }

    return dccResult;
}

